  `score` double DEFAULT NULL,
  `label` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dailyChangePercent` double DEFAULT NULL,
  `sortOrder` int NOT NULL DEFAULT '0',
