  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `cmp` double DEFAULT NULL,
  `ema50` double DEFAULT NULL,
  `ema200` double DEFAULT NULL,
  `proximityToEma50Pct` double DEFAULT NULL,
  `recommendation` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
