  `scannedAt` timestamp NULL DEFAULT NULL,
  `recommendedBuyPrice` double DEFAULT NULL,
  `recommendedStopLoss` double DEFAULT NULL,
  `hotSignal` tinyint DEFAULT '0',
  `archived` tinyint NOT NULL DEFAULT '0',
  `archivedAt` timestamp NULL DEFAULT NULL,
  `profitPotential` double DEFAULT NULL,
  `note` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `lastSignalSentAt` timestamp NULL DEFAULT NULL,
  `signalExpiry` timestamp NULL DEFAULT NULL,
  `signalDate` timestamp NULL DEFAULT NULL,
  `mentorSources` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mentorConfidence` tinyint DEFAULT NULL COMMENT 'Phase 1: LLM confidence score 1-5',
  `signalBias` enum('LONG','SHORT','WATCH','REJECTED') COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Phase 1: Hebrew Slang Guard output',
  PRIMARY KEY (`id`),
  KEY `userAssets_userId_idx` (`userId`),
  KEY `userAssets_userId_archived_idx` (`userId`,`archived`)
